const fs = require('fs');
const path = require('path');

const today = new Date().toISOString().split('T')[0];
const dataDir = 'C:\\Users\\admin\\projects\\news-aggregator\\data\\news';
const filePath = path.join(dataDir, `${today}.json`);

if (!fs.existsSync(filePath)) {
  return [{
    json: {
      date: new Date().toLocaleDateString('vi-VN', {
        timeZone: 'Asia/Ho_Chi_Minh',
        day: '2-digit',
        month: '2-digit',
        year: 'numeric'
      }),
      totalArticles: 0,
      totalSources: 0,
      totalCategories: 0,
      categories: [],
      message: 'Không có dữ liệu cho hôm nay'
    }
  }];
}

const articles = JSON.parse(fs.readFileSync(filePath, 'utf8'));

const categories = {};
articles.forEach(article => {
  const cat = article.category || 'Khác';
  if (!categories[cat]) {
    categories[cat] = [];
  }
  categories[cat].push(article);
});

const categoryArray = Object.keys(categories).map(name => ({
  name,
  articles: categories[name]
}));

return [{
  json: {
    date: new Date().toLocaleDateString('vi-VN', {
      timeZone: 'Asia/Ho_Chi_Minh',
      day: '2-digit',
      month: '2-digit',
      year: 'numeric'
    }),
    totalArticles: articles.length,
    totalSources: [...new Set(articles.map(a => a.source))].length,
    totalCategories: categoryArray.length,
    categories: categoryArray
  }
}];

const fs = require('fs');

const templatePath = 'C:\\Users\\admin\\projects\\news-aggregator\\templates\\email-report.html';
let templateContent = fs.readFileSync(templatePath, 'utf8');

const data = items[0].json;

let html = templateContent;
html = html.replace('{{date}}', data.date);
html = html.replace('{{totalArticles}}', data.totalArticles);
html = html.replace('{{totalSources}}', data.totalSources);
html = html.replace('{{totalCategories}}', data.totalCategories);

let categoriesHtml = '';
data.categories.forEach(category => {
  categoriesHtml += `
    <div class="news-section">
      <h2 class="category-title">${category.name}</h2>
  `;

  category.articles.forEach(article => {
    categoriesHtml += `
      <div class="news-item">
        <div class="news-title">
          <a href="${article.link}" target="_blank">${article.title}</a>
        </div>
        <div class="news-meta">
          <span class="news-source">${article.source}</span> •
          <span>${article.pubDate}</span>
        </div>
        <div class="news-description">
          ${article.description}
        </div>
      </div>
    `;
  });

  categoriesHtml += `</div>`;
});

html = html.replace('{{#each categories}}', '');
html = html.replace('{{/each}}', '');
html = html.replace('{{this.name}}', '');
html = html.replace('{{#each this.articles}}', '');
html = html.replace('{{this.link}}', '');
html = html.replace('{{this.title}}', '');
html = html.replace('{{this.source}}', '');
html = html.replace('{{this.pubDate}}', '');
html = html.replace('{{this.description}}', '');

const insertPosition = html.indexOf('<div class="footer">');
html = html.slice(0, insertPosition) + categoriesHtml + html.slice(insertPosition);

return [{
  json: {
    html,
    subject: `📰 Báo cáo Tin tức - ${data.date}`,
    totalArticles: data.totalArticles
  }
}];

return [{
  json: {
    message: 'Không có dữ liệu để gửi báo cáo',
    timestamp: new Date().toLocaleString('vi-VN', {
      timeZone: 'Asia/Ho_Chi_Minh'
    })
  }
}];
